import React, { useState, useEffect } from 'react';
import { costsAPI } from '../services/api';
import toast from 'react-hot-toast';
import {
  Plus,
  Search,
  DollarSign,
  Calendar,
  Tag,
  Edit,
  Trash2
} from 'lucide-react';

const Costs = () => {
  const [costs, setCosts] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchCosts();
  }, []);

  const fetchCosts = async () => {
    try {
      const response = await costsAPI.getAll();
      setCosts(response.data.data);
    } catch (error) {
      toast.error('Error al cargar costos');
    } finally {
      setLoading(false);
    }
  };

  const formatCurrency = (amount) => {
    return new Intl.NumberFormat('es-MX', {
      style: 'currency',
      currency: 'MXN'
    }).format(amount);
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary-600"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-semibold text-gray-900">Costos</h1>
          <p className="mt-1 text-sm text-gray-600">
            Gestiona los costos fijos y variables del negocio
          </p>
        </div>
        <button className="btn btn-primary btn-md">
          <Plus className="h-4 w-4 mr-2" />
          Nuevo Costo
        </button>
      </div>

      {/* Costs Table */}
      <div className="card">
        <div className="overflow-x-auto">
          <table className="table">
            <thead>
              <tr>
                <th>Descripción</th>
                <th>Categoría</th>
                <th>Tipo</th>
                <th>Monto</th>
                <th>Fecha</th>
                <th>Frecuencia</th>
                <th>Acciones</th>
              </tr>
            </thead>
            <tbody>
              {costs.map((cost) => (
                <tr key={cost._id}>
                  <td className="font-medium">{cost.description}</td>
                  <td>
                    <span className="capitalize badge badge-info">
                      {cost.category}
                    </span>
                  </td>
                  <td>
                    <span className={`capitalize badge badge-${
                      cost.type === 'fijo' ? 'success' : 'warning'
                    }`}>
                      {cost.type}
                    </span>
                  </td>
                  <td className="text-right font-medium">
                    {formatCurrency(cost.amount)}
                  </td>
                  <td>
                    {new Date(cost.date).toLocaleDateString('es-MX')}
                  </td>
                  <td>
                    <span className="capitalize">{cost.frequency}</span>
                  </td>
                  <td>
                    <div className="flex items-center space-x-2">
                      <button className="text-primary-600 hover:text-primary-900">
                        <Edit className="h-4 w-4" />
                      </button>
                      <button className="text-danger-600 hover:text-danger-900">
                        <Trash2 className="h-4 w-4" />
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default Costs;
